1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.10;
3	
4	const BLOCK_OF_THREE_PRICE = 60;
5	
6	const BASE_PRICE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	};
13	
14	function itemPremium(items: { type: string }[]): number {
15	  const counts: Record<string, number> = {};
16	  for (const item of items) {
17	    counts[item.type] = (counts[item.type] || 0) + 1;
18	  }
19	
20	  let totalBase = 0;
21	  for (const type in counts) {
22	    const count = counts[type];
23	    if (count === 3) {
24	      totalBase += BLOCK_OF_THREE_PRICE;
25	    } else {
26	      totalBase += count * BASE_PRICE[type];
27	    }
28	  }
29	
30	  return totalBase + totalBase * FIRST_INSURANCE_RATE;
31	}
32	
33	export function quote(
34	  policy: { customer: { years: number }; items: { type: string }[] },
35	  _options: { isFollowUp: boolean }
36	): { premium: number } {
37	  return { premium: itemPremium(policy.items) + PROCESSING_FEE };
38	}
